VALUES (1, 'Atomic Habits', 'James Clear', 'https://m.media-amazon.com/images/I/81bGKUa1e0L._AC_UF1000,1000_QL80_.jpg', 'A comprehensive, practical guide on how to change your habits and get 1% better every day.', 'James Clear was severely injured in a baseball accident in high school. His recovery forced him to rely on small, daily habits to rebuild his life.', 'EASY', '320 pages', 'Actionable, Clear, Direct', 'Actionable advice, clear frameworks, real-world examples.', 'Do not judge it as just another motivation book; it is a systems-design manual for human behavior.', 'You will walk away with a functional system to build good habits and break bad ones.', 6.5, 5, 'YES', 95, 'High - saves hours of wasted effort');
INSERT INTO book_categories (book_id, category_id) VALUES (1, 4), (1, 1);
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (1, 'Highly practical frameworks that actually work in real life.');
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (1, 'Avoids fluff and gets straight to the point.');
INSERT INTO external_links (book_id, label, url) VALUES (1, 'Amazon', 'https://www.amazon.com/Atomic-Habits-Proven-Build-Break/dp/0735211299');

-- Book 2
INSERT INTO books (id, title, author_name, cover_image, about_description, author_true_story, difficulty_level, length_label, language_tone, what_to_expect, how_not_to_judge, expected_outcome, expected_time_investment, our_rating, verdict, confidence_percentage, estimated_roi)
VALUES (2, 'Thinking, Fast and Slow', 'Daniel Kahneman', 'https://m.media-amazon.com/images/I/71f6Dcg9ENL._AC_UF1000,1000_QL80_.jpg', 'A deep dive into the two systems that drive the way we think—System 1 (fast, intuitive, emotional) and System 2 (slower, more deliberative, and more logical).', 'Daniel Kahneman won the Nobel Prize in Economic Sciences despite being a psychologist by training, largely for the work detailed in this book.', 'CHALLENGING', '499 pages', 'Academic, Dense, Fascinating', 'Dense psychological studies, statistical concepts, deep insights into human error.', 'Do not expect a light beach read; it requires active concentration.', 'You will recognize cognitive biases in yourself and others.', 15.0, 4, 'CONDITIONAL', 80, 'Moderate - fundamental knowledge but takes effort');
INSERT INTO book_categories (book_id, category_id) VALUES (2, 1), (2, 2);
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (2, 'Incredible insights into human psychology.');
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (2, 'Can be very dry and academic at times.');
INSERT INTO external_links (book_id, label, url) VALUES (2, 'Amazon', 'https://www.amazon.com/Thinking-Fast-Slow-Daniel-Kahneman/dp/0374533555');

