INSERT INTO books (id, title, author_name, cover_image, about_description, author_true_story, difficulty_level, length_label, language_tone, what_to_expect, how_not_to_judge, expected_outcome, expected_time_investment, our_rating, verdict, confidence_percentage, estimated_roi)
VALUES (3, 'The Subtle Art of Not Giving a F*ck', 'Mark Manson', 'https://m.media-amazon.com/images/I/71QKQ9mwV7L._AC_UF1000,1000_QL80_.jpg', 'A counterintuitive approach to living a good life by embracing negative experiences and choosing what truly matters.', 'Mark Manson started as a dating coach and blogger before evolving into a personal development author.', 'EASY', '224 pages', 'Irreverent, Conversational, Profane', 'Humorous anecdotes, stoic philosophy packaged for the modern reader, strong language.', 'Do not dismiss it because of the title; it is actually a surprisingly thoughtful book on Stoicism.', 'You will learn how to prioritize your values and ignore the noise.', 4.5, 4, 'YES', 90, 'High - rapid shift in perspective');
INSERT INTO book_categories (book_id, category_id) VALUES (3, 4);
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (3, 'A refreshing break from toxic positivity.');
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (3, 'Quick read that forces you to evaluate your priorities.');
INSERT INTO external_links (book_id, label, url) VALUES (3, 'Amazon', 'https://www.amazon.com/Subtle-Art-Not-Giving-Counterintuitive/dp/0062457713');

