INSERT INTO books (id, title, author_name, cover_image, about_description, author_true_story, difficulty_level, length_label, language_tone, what_to_expect, how_not_to_judge, expected_outcome, expected_time_investment, our_rating, verdict, confidence_percentage, estimated_roi)
VALUES (4, 'Dune', 'Frank Herbert', 'https://m.media-amazon.com/images/I/81ym3QUd3KL._AC_UF1000,1000_QL80_.jpg', 'A sweeping epic of political intrigue, religion, and ecology set on a desert planet.', 'Frank Herbert was a journalist who researched sand dunes for a magazine article, which evolved into a multi-decade obsession resulting in Dune.', 'CHALLENGING', '896 pages', 'Epic, Atmospheric, Complex', 'Deep world-building, philosophical musings, complex political plots.', 'Do not expect a fast-paced action movie; it is a slow burn.', 'An appreciation for one of the foundational texts of modern science fiction.', 25.0, 5, 'YES', 95, 'High - profound cultural literacy');
INSERT INTO book_categories (book_id, category_id) VALUES (4, 3);
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (4, 'Unmatched world-building and scale.');
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (4, 'Explores timeless themes of power and ecology.');
INSERT INTO external_links (book_id, label, url) VALUES (4, 'Amazon', 'https://www.amazon.com/Dune-Frank-Herbert/dp/0441172717');

