INSERT INTO books (id, title, author_name, cover_image, about_description, author_true_story, difficulty_level, length_label, language_tone, what_to_expect, how_not_to_judge, expected_outcome, expected_time_investment, our_rating, verdict, confidence_percentage, estimated_roi)
VALUES (5, 'Sapiens: A Brief History of Humankind', 'Yuval Noah Harari', 'https://m.media-amazon.com/images/I/713jIoMO3UL._AC_UF1000,1000_QL80_.jpg', 'Explores the history of the human species from the Stone Age up to the twenty-first century.', 'Harari originally published this in Hebrew, and its massive success led to its translation into over 60 languages.', 'MODERATE', '464 pages', 'Engaging, Broad, Thought-Provoking', 'Sweeping historical narratives, challenging assertions about human nature.', 'Do not treat it as a peer-reviewed historical text; it is a synthesis of many fields meant to provoke thought.', 'A unified view of human history and our place in the world.', 12.0, 5, 'YES', 85, 'High - completely changes how you view society');
INSERT INTO book_categories (book_id, category_id) VALUES (5, 5);
