INSERT INTO book_verdict_reasons (book_id, reason) VALUES (5, 'Provides a macro-perspective on humanity.');
INSERT INTO external_links (book_id, label, url) VALUES (5, 'Amazon', 'https://www.amazon.com/Sapiens-Humankind-Yuval-Noah-Harari/dp/0062316095');

