INSERT INTO books (id, title, author_name, cover_image, about_description, author_true_story, difficulty_level, length_label, language_tone, what_to_expect, how_not_to_judge, expected_outcome, expected_time_investment, our_rating, verdict, confidence_percentage, estimated_roi)
VALUES (6, 'The 4-Hour Workweek', 'Timothy Ferriss', 'https://m.media-amazon.com/images/I/81qW97ndkvL._AC_UF1000,1000_QL80_.jpg', 'A guide to escaping the 9-5 grind and living anywhere by building automated income streams.', 'Ferriss was dangerously overworked running a supplement company when he developed these principles out of pure necessity.', 'EASY', '396 pages', 'Enthusiastic, Entrepreneurial, Dated', 'Tactics for outsourcing, time management hacks, lifestyle design philosophy.', 'Do not take the "4 hours" literally; it is about maximizing leverage, not avoiding work altogether.', 'You will question traditional career paths and learn some useful efficiency hacks.', 8.0, 3, 'NO', 70, 'Low - mostly outdated tactics');
