INSERT INTO books (id, title, author_name, cover_image, about_description, author_true_story, difficulty_level, length_label, language_tone, what_to_expect, how_not_to_judge, expected_outcome, expected_time_investment, our_rating, verdict, confidence_percentage, estimated_roi)
VALUES (7, 'Meditations', 'Marcus Aurelius', 'https://m.media-amazon.com/images/I/81c2P6Bbn8L._AC_UF1000,1000_QL80_.jpg', 'The personal journal of a Roman Emperor, detailing his thoughts on Stoic philosophy.', 'Aurelius never intended for these notes to be published; they were his private reflections while on military campaigns.', 'MODERATE', '254 pages', 'Reflective, Aphoristic, Ancient', 'Short philosophical passages, reflections on death, duty, and emotional control.', 'Do not expect a structured treatise; it is a collection of fragmented thoughts.', 'A robust mental framework for dealing with adversity.', 6.0, 5, 'YES', 95, 'High - timeless wisdom for daily life');
INSERT INTO book_categories (book_id, category_id) VALUES (7, 2);
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (7, 'Provides immense perspective on human struggles.');
INSERT INTO book_verdict_reasons (book_id, reason) VALUES (7, 'Short passages make it easy to digest slowly.');
