-- Book 8
INSERT INTO books (id, title, author_name, cover_image, about_description, author_true_story, difficulty_level, length_label, language_tone, what_to_expect, how_not_to_judge, expected_outcome, expected_time_investment, our_rating, verdict, confidence_percentage, estimated_roi)
VALUES (8, 'Project Hail Mary', 'Andy Weir', 'https://m.media-amazon.com/images/I/811mXzGeE2L._AC_UF1000,1000_QL80_.jpg', 'A lone astronaut must save the Earth from disaster in this hard science fiction thriller.', 'Weir wrote The Martian as a blog serial before it became a massive hit; this book returns to that hard-science focus.', 'EASY', '496 pages', 'Fast-Paced, Scientific, Optimistic', 'Lots of math and physics problem-solving, witty inner monologue, thrilling pacing.', 'Do not be intimidated by the science; it is explained clearly and serves the plot.', 'A thrilling, fun ride that makes you appreciate science.', 14.0, 4, 'CONDITIONAL', 85, 'Moderate - highly entertaining if you like hard sci-fi');
